final class CatalogController
{
    private function admin(string $view,array $data=[]):string{return view($view,$data+['adminUser'=>Auth::user(),'notice'=>Session::flash('admin_notice'),'error'=>Session::flash('admin_error')],'layouts/admin');}
    public function products(Request $request):string{$items=Database::connection()->query("SELECT p.*,c.name category_name,COALESCE(v.price_minor,0) price_minor,COALESCE(v.stock_qty,0) stock_qty,COALESCE(m.path,'/assets/images/packaging-reference.png') image_path FROM products p LEFT JOIN categories c ON c.id=p.primary_category_id LEFT JOIN (SELECT product_id,MIN(price_minor) price_minor,SUM(stock_qty) stock_qty FROM product_variants GROUP BY product_id)v ON v.product_id=p.id LEFT JOIN product_images pi ON pi.product_id=p.id AND pi.is_primary=1 LEFT JOIN media_assets m ON m.id=pi.media_id WHERE p.deleted_at IS NULL ORDER BY p.updated_at DESC")->fetchAll();return $this->admin('admin/products',compact('items'));}
    public function productForm(Request $request,?string $id=null):string{$product=null;$variants=[];$selected=[];if($id){$s=Database::connection()->prepare('SELECT * FROM products WHERE id=?');$s->execute([$id]);$product=$s->fetch();if(!$product)throw new HttpException(404,'Produsul nu existÃ„Æ’.');$v=Database::connection()->prepare('SELECT * FROM product_variants WHERE product_id=? ORDER BY id');$v->execute([$id]);$variants=$v->fetchAll();$c=Database::connection()->prepare('SELECT category_id FROM product_categories WHERE product_id=?');$c->execute([$id]);$selected=$c->fetchAll(PDO::FETCH_COLUMN);} $categories=Database::connection()->query('SELECT * FROM categories WHERE deleted_at IS NULL ORDER BY sort_order,name')->fetchAll();return $this->admin('admin/product-form',compact('product','variants','selected','categories'));}
    public function saveProduct(Request $request,?string $id=null):never{$name=trim((string)$request->input('name',''));$slug=$this->slug((string)$request->input('slug',$name));$sku=trim((string)$request->input('sku',''));$status=(string)$request->input('status','draft');$isGiftBox=$request->input('is_gift_box')?1:0;$categories=array_values(array_unique(array_map('intval',(array)$request->input('categories',[]))));$primary=(int)$request->input('primary_category_id',0);if($name===''||$slug===''||$sku===''||!in_array($status,['draft','active','archived'],true)||!$categories||!in_array($primary,$categories,true)){throw new HttpException(422,'CompleteazÃ„Æ’ produsul, categoriile Ãˆâ„¢i categoria principalÃ„Æ’.');}$pdo=Database::connection();$pdo->beginTransaction();try{if($id){$old=$pdo->prepare('SELECT slug FROM products WHERE id=? FOR UPDATE');$old->execute([$id]);$oldSlug=$old->fetchColumn();if(!$oldSlug)throw new HttpException(404,'Produsul nu existÃ„Æ’.');$pdo->prepare('UPDATE products SET primary_category_id=?,name=?,slug=?,sku=?,material=?,short_description=?,description_html=?,status=?,is_featured=?,is_gift_box=?,robots_index=?,include_sitemap=?,seo_title=?,seo_description=?,published_at=IF(?=\'active\',COALESCE(published_at,NOW()),published_at),updated_at=NOW() WHERE id=?')->execute([$primary,$name,$slug,$sku,$request->input('material'),$request->input('short_description'),HtmlSanitizer::clean((string)$request->input('description_html','')),$status,$request->input('is_featured')?1:0,$isGiftBox,$request->input('robots_index')?1:0,$request->input('include_sitemap')?1:0,$request->input('seo_title'),$request->input('seo_description'),$status,$id]);if($oldSlug!==$slug){$pdo->prepare("INSERT INTO url_redirects (source_path,target_path,http_status,reason,entity_type,entity_id) VALUES (?,?,301,'Schimbare slug produs','product',?) ON DUPLICATE KEY UPDATE target_path=VALUES(target_path),http_status=301")->execute(['/produs/'.$oldSlug,'/produs/'.$slug,$id]);}}else{$pdo->prepare('INSERT INTO products (primary_category_id,name,slug,sku,material,short_description,description_html,status,is_featured,is_gift_box,robots_index,include_sitemap,seo_title,seo_description,published_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,IF(?=\'active\',NOW(),NULL))')->execute([$primary,$name,$slug,$sku,$request->input('material'),$request->input('short_description'),HtmlSanitizer::clean((string)$request->input('description_html','')),$status,$request->input('is_featured')?1:0,$isGiftBox,$request->input('robots_index')?1:0,$request->input('include_sitemap')?1:0,$request->input('seo_title'),$request->input('seo_description'),$status]);$id=(string)$pdo->lastInsertId();}$pdo->prepare('DELETE FROM product_categories WHERE product_id=?')->execute([$id]);$pc=$pdo->prepare('INSERT INTO product_categories (product_id,category_id,is_primary) VALUES (?,?,?)');foreach($categories as $category){$pc->execute([$id,$category,$category===$primary?1:0]);}$variantIds=(array)$request->input('variant_id',[]);$variantSkus=(array)$request->input('variant_sku',[]);$prices=(array)$request->input('variant_price',[]);$stocks=(array)$request->input('variant_stock',[]);foreach($variantSkus as $index=>$variantSku){$variantSku=trim((string)$variantSku);if($variantSku==='')continue;$price=(int)round(((float)($prices[$index]??0))*100);$stock=(int)($stocks[$index]??0);$variantId=(int)($variantIds[$index]??0);if($variantId){$pdo->prepare('UPDATE product_variants SET sku=?,price_minor=?,stock_qty=?,updated_at=NOW() WHERE id=? AND product_id=?')->execute([$variantSku,$price,$stock,$variantId,$id]);}else{$pdo->prepare('INSERT INTO product_variants (product_id,sku,price_minor,stock_qty,is_active) VALUES (?,?,?,?,1)')->execute([$id,$variantSku,$price,$stock]);}}$media=(new UploadService())->image('image',$name);if($media){$pdo->prepare('UPDATE product_images SET is_primary=0 WHERE product_id=?')->execute([$id]);$pdo->prepare('INSERT INTO product_images (product_id,media_id,alt_text,sort_order,is_primary) VALUES (?,?,?,0,1)')->execute([$id,$media,$name]);}$priceStatement=$pdo->prepare('SELECT MIN(price_minor) FROM product_variants WHERE product_id=? AND is_active=1');$priceStatement->execute([$id]);$boxPrice=(int)$priceStatement->fetchColumn();$imageStatement=$pdo->prepare('SELECT media_id FROM product_images WHERE product_id=? AND is_primary=1 ORDER BY id DESC LIMIT 1');$imageStatement->execute([$id]);$boxImage=(int)$imageStatement->fetchColumn()?:null;if($isGiftBox){$pdo->prepare("INSERT INTO gift_box_templates (product_id,image_id,name,slug,description,base_price_minor,min_components,max_components,is_active) VALUES (?,?,?,?,?,?,2,6,?) ON DUPLICATE KEY UPDATE product_id=VALUES(product_id),image_id=COALESCE(VALUES(image_id),image_id),name=VALUES(name),description=VALUES(description),base_price_minor=VALUES(base_price_minor),is_active=VALUES(is_active),updated_at=NOW()")->execute([$id,$boxImage,$name,$slug,$request->input('short_description'),$boxPrice,$status==='active'?1:0]);}else{$pdo->prepare('UPDATE gift_box_templates SET is_active=0,updated_at=NOW() WHERE product_id=?')->execute([$id]);}$pdo->prepare("INSERT INTO sitemap_events (entity_type,entity_id,event_type,payload_json,status,available_at) VALUES ('product',?,?,JSON_OBJECT('slug',?),'pending',NOW())")->execute([$id,$status==='active'?'published':'updated',$slug]);$pdo->prepare("INSERT INTO audit_logs (actor_user_id,action,target_type,target_id,ip_address) VALUES (?,'product.saved','product',?,?)")->execute([Auth::id(),$id,$_SERVER['REMOTE_ADDR']??null]);$pdo->commit();try{$stripe=(new StripeService())->syncProduct((int)$id);Session::flash('admin_notice',$stripe?'Produsul a fost salvat È™i sincronizat cu Stripe.':'Produsul a fost salvat.');}catch(\Throwable $stripeException){error_log('Stripe product sync failed for product '.$id.': '.$stripeException->getMessage());Session::flash('admin_error','Produsul a fost salvat, dar sincronizarea Stripe a eÈ™uat: '.mb_substr($stripeException->getMessage(),0,180));}Response::redirect('/admin/produse/'.$id.'/edit');}catch(\Throwable $e){if($pdo->inTransaction())$pdo->rollBack();throw $e;}}
    public function deleteProduct(Request $request,string $id):never
    {
        $pdo=Database::connection();
        $pdo->beginTransaction();
        try{
            $statement=$pdo->prepare('SELECT id,name,slug FROM products WHERE id=? AND deleted_at IS NULL FOR UPDATE');
            $statement->execute([(int)$id]);
            $product=$statement->fetch();
            if(!$product){throw new HttpException(404,'Produsul nu existÃ„Æ’ sau a fost deja Ãˆâ„¢ters.');}
            $pdo->prepare("UPDATE products SET status='archived',robots_index=0,include_sitemap=0,deleted_at=NOW(),updated_at=NOW() WHERE id=?")->execute([(int)$id]);
            $pdo->prepare('UPDATE product_variants SET is_active=0,updated_at=NOW() WHERE product_id=?')->execute([(int)$id]);
            $pdo->prepare("INSERT INTO url_redirects (source_path,target_path,http_status,reason,entity_type,entity_id) VALUES (?,?,301,'Produs Ãˆâ„¢ters din catalog','product',?) ON DUPLICATE KEY UPDATE target_path=VALUES(target_path),http_status=301,reason=VALUES(reason)")->execute(['/produs/'.$product['slug'],'/shop',(int)$id]);
            $pdo->prepare("INSERT INTO sitemap_events (entity_type,entity_id,event_type,payload_json,status,available_at) VALUES ('product',?,'deleted',JSON_OBJECT('slug',?),'pending',NOW())")->execute([(int)$id,$product['slug']]);
            $pdo->prepare("INSERT INTO audit_logs (actor_user_id,action,target_type,target_id,ip_address) VALUES (?,'product.deleted','product',?,?)")->execute([Auth::id(),(int)$id,$_SERVER['REMOTE_ADDR']??null]);
            $pdo->commit();
            try{(new StripeService())->archiveProduct((int)$id);Session::flash('admin_notice','Produsul a fost arhivat È™i sincronizat cu Stripe.');}catch(\Throwable $stripeException){error_log('Stripe product archive failed for product '.$id.': '.$stripeException->getMessage());Session::flash('admin_error','Produsul a fost arhivat local, dar Stripe nu a putut fi actualizat: '.mb_substr($stripeException->getMessage(),0,180));}
            Response::redirect('/admin/produse');
        }catch(\Throwable $exception){
            if($pdo->inTransaction()){$pdo->rollBack();}
            throw $exception;
        }
    }
    public function categories(Request $request):string{$items=Database::connection()->query('SELECT c.*,p.name parent_name,(SELECT COUNT(*) FROM product_categories pc WHERE pc.category_id=c.id) product_count,(SELECT COUNT(*) FROM categories child WHERE child.parent_id=c.id AND child.deleted_at IS NULL) child_count FROM categories c LEFT JOIN categories p ON p.id=c.parent_id WHERE c.deleted_at IS NULL ORDER BY c.sort_order,c.name')->fetchAll();return $this->admin('admin/categories',compact('items'));}
    public function categoryForm(Request $request,?string $id=null):string{$category=null;if($id){$s=Database::connection()->prepare('SELECT * FROM categories WHERE id=?');$s->execute([$id]);$category=$s->fetch();if(!$category)throw new HttpException(404,'Categoria nu existÃ„Æ’.');}$parents=Database::connection()->query('SELECT id,name,parent_id FROM categories WHERE deleted_at IS NULL ORDER BY name')->fetchAll();return $this->admin('admin/category-form',compact('category','parents'));}
    public function saveCategory(Request $request,?string $id=null):never{$name=trim((string)$request->input('name',''));$slug=$this->slug((string)$request->input('slug',$name));$parent=(int)$request->input('parent_id',0)?:null;if($name===''||$slug==='')throw new HttpException(422,'Numele Ãˆâ„¢i slugul sunt obligatorii.');if($id&&$parent===(int)$id)throw new HttpException(422,'Categoria nu poate fi propriul pÃ„Æ’rinte.');$image=(new UploadService())->image('image',$name);$pdo=Database::connection();if($id){$old=$pdo->prepare('SELECT slug FROM categories WHERE id=?');$old->execute([$id]);$oldSlug=$old->fetchColumn();$pdo->prepare('UPDATE categories SET parent_id=?,image_id=COALESCE(?,image_id),name=?,slug=?,description=?,is_active=?,show_in_menu=?,sort_order=?,seo_title=?,seo_description=? WHERE id=?')->execute([$parent,$image,$name,$slug,$request->input('description'),$request->input('is_active')?1:0,$request->input('show_in_menu')?1:0,(int)$request->input('sort_order',0),$request->input('seo_title'),$request->input('seo_description'),$id]);if($oldSlug&&$oldSlug!==$slug){$pdo->prepare("INSERT INTO url_redirects (source_path,target_path,http_status,reason,entity_type,entity_id) VALUES (?,?,301,'Schimbare slug categorie','category',?) ON DUPLICATE KEY UPDATE target_path=VALUES(target_path)")->execute(['/categorie/'.$oldSlug,'/categorie/'.$slug,$id]);}}else{$pdo->prepare('INSERT INTO categories (parent_id,image_id,name,slug,description,is_active,show_in_menu,sort_order,seo_title,seo_description) VALUES (?,?,?,?,?,?,?,?,?,?)')->execute([$parent,$image,$name,$slug,$request->input('description'),$request->input('is_active')?1:0,$request->input('show_in_menu')?1:0,(int)$request->input('sort_order',0),$request->input('seo_title'),$request->input('seo_description')]);$id=(string)$pdo->lastInsertId();}Response::redirect('/admin/categorii/'.$id.'/edit');}
    public function deleteCategory(Request $request,string $id):never
    {
        $pdo=Database::connection();
        $statement=$pdo->prepare('SELECT c.id,c.name,c.slug,(SELECT COUNT(*) FROM product_categories pc WHERE pc.category_id=c.id) product_count,(SELECT COUNT(*) FROM categories child WHERE child.parent_id=c.id AND child.deleted_at IS NULL) child_count FROM categories c WHERE c.id=? AND c.deleted_at IS NULL');
        $statement->execute([(int)$id]);
        $category=$statement->fetch();
        if(!$category){throw new HttpException(404,'Categoria nu existÃ„Æ’ sau a fost deja Ãˆâ„¢tearsÃ„Æ’.');}
        if((int)$category['product_count']>0||(int)$category['child_count']>0){throw new HttpException(422,'MutÃ„Æ’ mai ÃƒÂ®ntÃƒÂ¢i produsele Ãˆâ„¢i subcategoriile ÃƒÂ®nainte de Ãˆâ„¢tergere.');}
        $pdo->beginTransaction();
        try{
            $pdo->prepare('UPDATE categories SET is_active=0,show_in_menu=0,deleted_at=NOW(),updated_at=NOW() WHERE id=?')->execute([(int)$id]);
            $pdo->prepare("INSERT INTO url_redirects (source_path,target_path,http_status,reason,entity_type,entity_id) VALUES (?,?,301,'Categorie Ãˆâ„¢tearsÃ„Æ’ din catalog','category',?) ON DUPLICATE KEY UPDATE target_path=VALUES(target_path),http_status=301,reason=VALUES(reason)")->execute(['/categorie/'.$category['slug'],'/shop',(int)$id]);
            $pdo->prepare("INSERT INTO sitemap_events (entity_type,entity_id,event_type,payload_json,status,available_at) VALUES ('category',?,'deleted',JSON_OBJECT('slug',?),'pending',NOW())")->execute([(int)$id,$category['slug']]);
            $pdo->prepare("INSERT INTO audit_logs (actor_user_id,action,target_type,target_id,ip_address) VALUES (?,'category.deleted','category',?,?)")->execute([Auth::id(),(int)$id,$_SERVER['REMOTE_ADDR']??null]);
            $pdo->commit();
            Response::redirect('/admin/categorii');
        }catch(\Throwable $exception){if($pdo->inTransaction()){$pdo->rollBack();}throw $exception;}
    }
    private function slug(string $value):string{$value=mb_strtolower(trim($value));$map=['Ã„Æ’'=>'a','ÃƒÂ¢'=>'a','ÃƒÂ®'=>'i','Ãˆâ„¢'=>'s','Ã…Å¸'=>'s','Ãˆâ€º'=>'t','Ã…Â£'=>'t'];$value=strtr($value,$map);$value=preg_replace('/[^a-z0-9]+/','-',$value)??'';return trim($value,'-');}
}

